VALUES
  ('police-8b7f1efc-moex-00497', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '依警察遴選第三人蒐集資料辦法中，關於線民遴選管理規定，下列敘述何者正確？', '["警察遴選第三人時，應以書面，陳報內政部警政署署長核准後實施", "遴選第三人經核准後，除最近2年內曾任第三人者外，應實施訓練", "警察遴選第三人蒐集資料之期間不得逾2年", "第三人之真實姓名及身分應予保密，並以代號或化名為之。第三人之簽名以蓋印章代之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "c797e2a17bd8", "answer_pdf_sha1": "5cf90af717ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1309", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00498', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '有關筆錄製作，下列敘述何者正確？', '["筆錄不得竄改、挖補或留空行，如有增刪更改，應於筆錄右方空白處記明更改字數", "筆錄經受詢問人確認無誤後，應由受詢人於緊接其記載之末行簽名、蓋章或按指印（三者擇一， 如按指印以左拇指為原則）", "與其他司法警察機關共同偵辦刑案，對於同一犯罪嫌疑人之筆錄，不可分由不同機關人員詢問 及製作", "受詢問人拒絕回答或拒絕在筆錄上簽名、蓋章或按指印時，得強制為之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "c797e2a17bd8", "answer_pdf_sha1": "5cf90af717ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1309", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00499', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '有關通訊監察，下列敘述何者錯誤？', '["檢察官受理聲請案件，應於6小時內核復；如案情複雜，得經檢察長同意延長6小時", "法院於接獲檢察官核轉受理聲請案件，應於48小時內核復", "執行機關應於執行監聽期間內，每15日至少作成一次以上之報告書", "法院應設置專責窗口受理檢察官以口頭通知先予執行通訊監察之聲請案件，並應於48小時內 補發通訊監察書"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "c797e2a17bd8", "answer_pdf_sha1": "5cf90af717ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1309", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00500', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '下列何者無法經由通聯紀錄分析加以研判？', '["嫌犯認識及交往密切之對象", "嫌犯生活作息情形及涉案之可能性", "嫌犯活動區域範圍及案發時發話者是否在場", "嫌犯通話明細及對話內容"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "c797e2a17bd8", "answer_pdf_sha1": "5cf90af717ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1309", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00501', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '對使用於網路犯罪之電腦執行搜索時所應注意事項，下列敘述何者錯誤？', '["應讓受搜索人與電腦保持適當距離，避免受搜索人接觸電腦刪除檔案、證據", "勿安裝或拷貝任何程式、檔案至受搜索人的電腦中", "搜索對象如為學校，應會同該校長執行之，搜索時應注意態度與技巧", "電腦檔案之證據應當場列印，並請受搜索人簽名按指印"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "c797e2a17bd8", "answer_pdf_sha1": "5cf90af717ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1309", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00502', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '依家庭暴力防治法規定，下列敘述何者正確？', '["所稱主管機關：在中央為內政部；在直轄市為直轄市政府；在縣（市）為縣（市）政府", "本法所定家庭成員，不包括前配偶及其未成年子女", "通常保護令之有效期間為2年以下，自核發時起生效", "高級中等以下學校每學年應有8小時以上之家庭暴力防治課程。但得於總時數不變下，彈性實施"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "c797e2a17bd8", "answer_pdf_sha1": "5cf90af717ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1309", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00503', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '依毒品危害防制條例，毒品依其成癮性、濫用性及對社會危害性，分為四級，下列敘述何者 錯誤？', '["愷他命（ketamine）列第三級毒品", "甲氧基乙基安非他命（Methoxyethylamphetamine、MEA）列第二級毒品", "安非他命（Amphetamine）列第二級毒品", "大麻浸膏（Cannabisextracts）列第二級毒品"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "c797e2a17bd8", "answer_pdf_sha1": "5cf90af717ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1309", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00504', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '司法警察官或司法警察因調查犯罪嫌疑人犯罪情形及蒐集證據之必要，得通知證人到場詢問。證 人之權利義務，下列敘述何者正確？', '["有緘默權保障", "在場供述義務", "供述真實義務", "有拒絕證言權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "c797e2a17bd8", "answer_pdf_sha1": "5cf90af717ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1309", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00505', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '警察接獲線報，指民眾A常於夜店兜售安非他命咖啡包，經派員警於該店門口盤查A，A見警作 賊心虛主動交出持有之安非他命咖啡包。下列敘述何者錯誤？', '["可帶A返家搜索是否尚有毒品", "得搜索A身體及所攜帶的背包", "得逕行搜索A停放於附近之車輛", "得帶A至醫院採取尿液"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "c797e2a17bd8", "answer_pdf_sha1": "5cf90af717ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1309", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 17, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00506', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '民眾A與友人飲酒後仍執意駕車返家，卻於途中撞上安全島、不省人事。警察前來處理，見A無 明顯傷勢，但有酒味，為確認A是否酒駕，擬對其抽血採驗。下列敘述何者正確？', '["得以現行犯逮捕A，並送醫療院所直接採驗", "應通知A的家人，並經其同意送醫療院所採驗", "應報請檢察官核發鑑定許可書，送醫療院所採驗", "應報請法官核發鑑定許可書，送醫療院所採驗"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "c797e2a17bd8", "answer_pdf_sha1": "5cf90af717ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1309", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL)
